package test.rice.basegen;

import main.rice.basegen.BaseSetGenerator;
import main.rice.node.*;
import main.rice.obj.*;
import main.rice.test.TestCase;
import org.junit.jupiter.api.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;

/**
 * Additional tests for BaseSetGenerator covering edge cases.
 */
class AgentBaseSetTests {

    private static PyIntNode createIntNode(List<Integer> exDomain, List<Integer> ranDomain) {
        PyIntNode node = new PyIntNode();
        node.setExDomain(new ArrayList<>(exDomain));
        node.setRanDomain(new ArrayList<>(ranDomain));
        return node;
    }

    @Test
    void testExSingleArgSingleValue() {
        PyIntNode node = createIntNode(Arrays.asList(42), Arrays.asList(42));
        BaseSetGenerator gen = new BaseSetGenerator(Arrays.asList(node), 0);

        Set<TestCase> result = gen.genExTests();
        assertEquals(1, result.size());
        assertTrue(result.contains(new TestCase(Arrays.asList(new PyIntObj(42)))));
    }

    @Test
    void testExThreeArgsCartesian() {
        PyIntNode n1 = createIntNode(Arrays.asList(1, 2), Arrays.asList(1));
        PyIntNode n2 = createIntNode(Arrays.asList(3), Arrays.asList(3));
        PyIntNode n3 = createIntNode(Arrays.asList(4, 5), Arrays.asList(4));
        BaseSetGenerator gen = new BaseSetGenerator(Arrays.asList(n1, n2, n3), 0);

        Set<TestCase> result = gen.genExTests();
        // 2 * 1 * 2 = 4
        assertEquals(4, result.size());
    }

    @Test
    void testBaseSetZeroRand() {
        PyIntNode node = createIntNode(Arrays.asList(1, 2), Arrays.asList(1, 2));
        BaseSetGenerator gen = new BaseSetGenerator(Arrays.asList(node), 0);

        List<TestCase> result = gen.genBaseSet();
        assertEquals(2, result.size());
    }

    @Test
    void testExWithListArg() {
        PyIntNode intNode = createIntNode(Arrays.asList(1, 2), Arrays.asList(1));
        PyListNode<PyIntObj> listNode = new PyListNode<>(intNode);
        listNode.setExDomain(Arrays.asList(1));
        listNode.setRanDomain(Arrays.asList(1));

        BaseSetGenerator gen = new BaseSetGenerator(Arrays.asList(listNode), 0);
        Set<TestCase> result = gen.genExTests();
        // Lists of length 1 from {1, 2}: [1], [2]
        assertEquals(2, result.size());
    }

    @Test
    void testExWithMixedArgs() {
        PyIntNode intNode = createIntNode(Arrays.asList(1, 2), Arrays.asList(1));
        PyBoolNode boolNode = new PyBoolNode();
        boolNode.setExDomain(Arrays.asList(true, false));
        boolNode.setRanDomain(Arrays.asList(true));

        BaseSetGenerator gen = new BaseSetGenerator(Arrays.asList(intNode, boolNode), 0);
        Set<TestCase> result = gen.genExTests();
        // 2 * 2 = 4
        assertEquals(4, result.size());
    }

    @Test
    void testRandUniqueFromEx() {
        // Verify rand tests don't overlap with ex tests
        PyIntNode node = createIntNode(Arrays.asList(1), Arrays.asList(100));
        BaseSetGenerator gen = new BaseSetGenerator(Arrays.asList(node), 1);

        List<TestCase> result = gen.genBaseSet();
        // 1 ex + 1 rand (no overlap since domains differ)
        assertEquals(2, result.size());

        TestCase exTest = new TestCase(Arrays.asList(new PyIntObj(1)));
        TestCase randTest = new TestCase(Arrays.asList(new PyIntObj(100)));
        assertTrue(result.contains(exTest));
        assertTrue(result.contains(randTest));
    }
}

package test.rice.node;

import main.rice.node.*;
import main.rice.obj.*;
import org.junit.jupiter.api.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;

/**
 * Additional tests for PyNode classes covering edge cases.
 */
class AgentNodeTests {

    private static PyIntNode createIntNode(List<Integer> exDomain, List<Integer> ranDomain) {
        PyIntNode node = new PyIntNode();
        node.setExDomain(new ArrayList<>(exDomain));
        node.setRanDomain(new ArrayList<>(ranDomain));
        return node;
    }

    // ==================== PyIntNode Tests ====================

    @Test
    void testIntNodeGenExValsSingle() {
        PyIntNode node = createIntNode(Arrays.asList(42), Arrays.asList(42));
        Set<PyIntObj> result = node.genExVals();
        assertEquals(1, result.size());
        assertTrue(result.contains(new PyIntObj(42)));
    }

    @Test
    void testIntNodeGenExValsNegative() {
        PyIntNode node = createIntNode(Arrays.asList(-1, 0, 1), Arrays.asList(-1));
        Set<PyIntObj> result = node.genExVals();
        assertEquals(3, result.size());
        assertTrue(result.contains(new PyIntObj(-1)));
        assertTrue(result.contains(new PyIntObj(0)));
        assertTrue(result.contains(new PyIntObj(1)));
    }

    @Test
    void testIntNodeGenRandValInDomain() {
        PyIntNode node = createIntNode(Arrays.asList(1), Arrays.asList(10, 20, 30));
        PyIntObj result = node.genRandVal();
        assertTrue(Arrays.asList(10, 20, 30).contains(result.getValue()));
    }

    @Test
    void testIntNodeGetRanDomain() {
        PyIntNode node = createIntNode(Arrays.asList(1, 2), Arrays.asList(3, 4, 5));
        assertEquals(Arrays.asList(3, 4, 5), node.getRanDomain());
    }

    // ==================== PyBoolNode Tests ====================

    @Test
    void testBoolNodeGenExVals() {
        PyBoolNode node = new PyBoolNode();
        node.setExDomain(Arrays.asList(true, false));
        node.setRanDomain(Arrays.asList(true));

        Set<PyBoolObj> result = node.genExVals();
        assertEquals(2, result.size());
        assertTrue(result.contains(new PyBoolObj(true)));
        assertTrue(result.contains(new PyBoolObj(false)));
    }

    @Test
    void testBoolNodeGenRandVal() {
        PyBoolNode node = new PyBoolNode();
        node.setExDomain(Arrays.asList(true));
        node.setRanDomain(Arrays.asList(false));

        PyBoolObj result = node.genRandVal();
        assertEquals(new PyBoolObj(false), result);
    }

    // ==================== PyFloatNode Tests ====================

    @Test
    void testFloatNodeGenExVals() {
        PyFloatNode node = new PyFloatNode();
        node.setExDomain(Arrays.asList(1.0, 2.5, 3.7));
        node.setRanDomain(Arrays.asList(1.0));

        Set<PyFloatObj> result = node.genExVals();
        assertEquals(3, result.size());
        assertTrue(result.contains(new PyFloatObj(1.0)));
        assertTrue(result.contains(new PyFloatObj(2.5)));
        assertTrue(result.contains(new PyFloatObj(3.7)));
    }

    // ==================== PyListNode Tests ====================

    @Test
    void testListNodeEmptyOnly() {
        PyIntNode intNode = createIntNode(Arrays.asList(1, 2), Arrays.asList(1, 2));
        PyListNode<PyIntObj> listNode = new PyListNode<>(intNode);
        listNode.setExDomain(Arrays.asList(0));

        Set<PyListObj<PyIntObj>> result = listNode.genExVals();
        assertEquals(1, result.size());
        assertTrue(result.contains(new PyListObj<>(new ArrayList<>())));
    }

    @Test
    void testListNodeMultipleLengths() {
        PyIntNode intNode = createIntNode(Arrays.asList(1), Arrays.asList(1));
        PyListNode<PyIntObj> listNode = new PyListNode<>(intNode);
        listNode.setExDomain(Arrays.asList(0, 1, 2));

        Set<PyListObj<PyIntObj>> result = listNode.genExVals();
        // Length 0: [] -> 1
        // Length 1: [1] -> 1
        // Length 2: [1, 1] -> 1
        assertEquals(3, result.size());
    }

    @Test
    void testListNodeThreeElementsTwoLen() {
        PyIntNode intNode = createIntNode(Arrays.asList(1, 2, 3), Arrays.asList(1));
        PyListNode<PyIntObj> listNode = new PyListNode<>(intNode);
        listNode.setExDomain(Arrays.asList(2));

        Set<PyListObj<PyIntObj>> result = listNode.genExVals();
        // 3^2 = 9 sequences with repetition
        assertEquals(9, result.size());
    }

    @Test
    void testListNodeGetLeftChild() {
        PyIntNode intNode = createIntNode(Arrays.asList(1), Arrays.asList(1));
        PyListNode<PyIntObj> listNode = new PyListNode<>(intNode);
        assertSame(intNode, listNode.getLeftChild());
    }

    @Test
    void testListNodeGetRightChildNull() {
        PyIntNode intNode = createIntNode(Arrays.asList(1), Arrays.asList(1));
        PyListNode<PyIntObj> listNode = new PyListNode<>(intNode);
        assertNull(listNode.getRightChild());
    }

    // ==================== PySetNode Tests ====================

    @Test
    void testSetNodeEmptyOnly() {
        PyIntNode intNode = createIntNode(Arrays.asList(1, 2, 3), Arrays.asList(1));
        PySetNode<PyIntObj> setNode = new PySetNode<>(intNode);
        setNode.setExDomain(Arrays.asList(0));

        Set<PySetObj<PyIntObj>> result = setNode.genExVals();
        assertEquals(1, result.size());
        assertTrue(result.contains(new PySetObj<>(new HashSet<>())));
    }

    @Test
    void testSetNodeThreeChooseTwo() {
        PyIntNode intNode = createIntNode(Arrays.asList(1, 2, 3), Arrays.asList(1));
        PySetNode<PyIntObj> setNode = new PySetNode<>(intNode);
        setNode.setExDomain(Arrays.asList(2));

        Set<PySetObj<PyIntObj>> result = setNode.genExVals();
        // C(3, 2) = 3
        assertEquals(3, result.size());
    }

    @Test
    void testSetNodeLengthTooLarge() {
        PyIntNode intNode = createIntNode(Arrays.asList(1, 2), Arrays.asList(1));
        PySetNode<PyIntObj> setNode = new PySetNode<>(intNode);
        setNode.setExDomain(Arrays.asList(3)); // Can't make set of 3 from 2 elements

        Set<PySetObj<PyIntObj>> result = setNode.genExVals();
        assertEquals(0, result.size());
    }

    @Test
    void testSetNodeMultipleLengths() {
        PyIntNode intNode = createIntNode(Arrays.asList(1, 2, 3), Arrays.asList(1));
        PySetNode<PyIntObj> setNode = new PySetNode<>(intNode);
        setNode.setExDomain(Arrays.asList(0, 1, 2));

        Set<PySetObj<PyIntObj>> result = setNode.genExVals();
        // C(3,0)=1, C(3,1)=3, C(3,2)=3 -> total 7
        assertEquals(7, result.size());
    }

    // ==================== PyTupleNode Tests ====================

    @Test
    void testTupleNodeTwoLenTwo() {
        PyIntNode intNode = createIntNode(Arrays.asList(1, 2), Arrays.asList(1));
        PyTupleNode<PyIntObj> tupleNode = new PyTupleNode<>(intNode);
        tupleNode.setExDomain(Arrays.asList(2));

        Set<PyTupleObj<PyIntObj>> result = tupleNode.genExVals();
        // 2^2 = 4
        assertEquals(4, result.size());
    }

    @Test
    void testTupleNodeGetLeftChild() {
        PyIntNode intNode = createIntNode(Arrays.asList(1), Arrays.asList(1));
        PyTupleNode<PyIntObj> tupleNode = new PyTupleNode<>(intNode);
        assertSame(intNode, tupleNode.getLeftChild());
    }

    // ==================== PyStringNode Tests ====================

    @Test
    void testStringNodeEmptyString() {
        PyStringNode stringNode = new PyStringNode("abc");
        stringNode.setExDomain(Arrays.asList(0));

        Set<PyStringObj> result = stringNode.genExVals();
        assertEquals(1, result.size());
        assertTrue(result.contains(new PyStringObj("")));
    }

    @Test
    void testStringNodeTwoCharsLenTwo() {
        PyStringNode stringNode = new PyStringNode("ab");
        stringNode.setExDomain(Arrays.asList(2));

        Set<PyStringObj> result = stringNode.genExVals();
        // 2^2 = 4: "aa", "ab", "ba", "bb"
        assertEquals(4, result.size());
        assertTrue(result.contains(new PyStringObj("aa")));
        assertTrue(result.contains(new PyStringObj("ab")));
        assertTrue(result.contains(new PyStringObj("ba")));
        assertTrue(result.contains(new PyStringObj("bb")));
    }

    @Test
    void testStringNodeMultipleLengths() {
        PyStringNode stringNode = new PyStringNode("a");
        stringNode.setExDomain(Arrays.asList(0, 1, 2));

        Set<PyStringObj> result = stringNode.genExVals();
        // 1 + 1 + 1 = 3: "", "a", "aa"
        assertEquals(3, result.size());
    }

    @Test
    void testStringNodeRandValLength() {
        PyStringNode stringNode = new PyStringNode("xyz");
        stringNode.setRanDomain(Arrays.asList(5));

        PyStringObj result = stringNode.genRandVal();
        assertEquals(5, result.getValue().size());
    }

    @Test
    void testStringNodeGetLeftChildNull() {
        PyStringNode stringNode = new PyStringNode("abc");
        assertNull(stringNode.getLeftChild());
    }

    // ==================== PyDictNode Tests ====================

    @Test
    void testDictNodeEmptyDict() {
        PyIntNode keyNode = createIntNode(Arrays.asList(1, 2), Arrays.asList(1));
        PyIntNode valNode = createIntNode(Arrays.asList(10, 20), Arrays.asList(10));
        PyDictNode<PyIntObj, PyIntObj> dictNode = new PyDictNode<>(keyNode, valNode);
        dictNode.setExDomain(Arrays.asList(0));

        Set<PyDictObj<PyIntObj, PyIntObj>> result = dictNode.genExVals();
        assertEquals(1, result.size());
        assertTrue(result.contains(new PyDictObj<>(new HashMap<>())));
    }

    @Test
    void testDictNodeTwoKeysTwoValsLenTwo() {
        PyIntNode keyNode = createIntNode(Arrays.asList(1, 2), Arrays.asList(1));
        PyIntNode valNode = createIntNode(Arrays.asList(10, 20), Arrays.asList(10));
        PyDictNode<PyIntObj, PyIntObj> dictNode = new PyDictNode<>(keyNode, valNode);
        dictNode.setExDomain(Arrays.asList(2));

        Set<PyDictObj<PyIntObj, PyIntObj>> result = dictNode.genExVals();
        // C(2,2)=1 key combo, 2^2=4 value assignments -> 4
        assertEquals(4, result.size());
    }

    @Test
    void testDictNodeGetLeftChild() {
        PyIntNode keyNode = createIntNode(Arrays.asList(1), Arrays.asList(1));
        PyIntNode valNode = createIntNode(Arrays.asList(10), Arrays.asList(10));
        PyDictNode<PyIntObj, PyIntObj> dictNode = new PyDictNode<>(keyNode, valNode);
        assertSame(keyNode, dictNode.getLeftChild());
    }

    @Test
    void testDictNodeThreeKeysTwoValsLenOne() {
        PyIntNode keyNode = createIntNode(Arrays.asList(1, 2, 3), Arrays.asList(1));
        PyIntNode valNode = createIntNode(Arrays.asList(10, 20), Arrays.asList(10));
        PyDictNode<PyIntObj, PyIntObj> dictNode = new PyDictNode<>(keyNode, valNode);
        dictNode.setExDomain(Arrays.asList(1));

        Set<PyDictObj<PyIntObj, PyIntObj>> result = dictNode.genExVals();
        // C(3,1)=3 key combos, each with 2 value options -> 6
        assertEquals(6, result.size());
    }

    // ==================== Nested Iterable Tests ====================

    @Test
    void testSetOfTuplesExhaustive() {
        PyIntNode intNode = createIntNode(Arrays.asList(1, 2), Arrays.asList(1));
        PyTupleNode<PyIntObj> tupleNode = new PyTupleNode<>(intNode);
        tupleNode.setExDomain(Arrays.asList(1));

        PySetNode<PyTupleObj<PyIntObj>> setNode = new PySetNode<>(tupleNode);
        setNode.setExDomain(Arrays.asList(2));

        Set<PySetObj<PyTupleObj<PyIntObj>>> result = setNode.genExVals();
        // Inner tuples: (1,), (2,) -> 2 options
        // Sets of size 2: C(2,2) = 1
        assertEquals(1, result.size());
    }

    @Test
    void testListOfListsExhaustive() {
        PyIntNode intNode = createIntNode(Arrays.asList(1), Arrays.asList(1));
        PyListNode<PyIntObj> innerList = new PyListNode<>(intNode);
        innerList.setExDomain(Arrays.asList(0, 1));

        PyListNode<PyListObj<PyIntObj>> outerList = new PyListNode<>(innerList);
        outerList.setExDomain(Arrays.asList(1));

        Set<PyListObj<PyListObj<PyIntObj>>> result = outerList.genExVals();
        // Inner list vals: [], [1] -> 2 options
        // Outer list of length 1: 2 options
        assertEquals(2, result.size());
    }
}

package main.rice.test;

import java.util.Map;
import java.util.Set;

/**
 * A class for storing the results of running a test suite on a set of student
 * implementations.
 */
public class TestResults {

    /**
     * A mapping from each file path to the set of test cases that the file failed.
     */
    private final Map<String, Set<TestCase>> results;

    /**
     * Constructor for TestResults.
     *
     * @param results a mapping from file paths to the test cases each file failed
     */
    public TestResults(Map<String, Set<TestCase>> results) {
        this.results = results;
    }

    /**
     * Returns the results mapping.
     *
     * @return the results mapping
     */
    public Map<String, Set<TestCase>> getResults() {
        return this.results;
    }
}

package main.rice.test;

import main.rice.obj.APyObj;
import java.util.ArrayList;
import java.util.List;

/**
 * A class representing a single test case, consisting of a list of arguments
 * (Python objects) to be passed to the function under test.
 */
public class TestCase {

    /**
     * The list of arguments for this test case.
     */
    private final List<APyObj> args;

    /**
     * Constructor for a TestCase; initializes its arguments to the input.
     *
     * @param args the arguments for this test case
     */
    public TestCase(List<? extends APyObj> args) {
        this.args = new ArrayList<>(args);
    }

    /**
     * Returns the arguments for this test case.
     *
     * @return the arguments
     */
    public List<APyObj> getArgs() {
        return this.args;
    }

    /**
     * Compares this test case to the input object by comparing arguments.
     *
     * @param obj the object to compare against
     * @return true if this is equivalent by value to obj; false otherwise
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof TestCase other)) {
            return false;
        }
        return this.args.equals(other.args);
    }

    /**
     * Computes a hash code based on this test case's arguments.
     *
     * @return the hash code for this test case
     */
    @Override
    public int hashCode() {
        return this.args.hashCode();
    }

    /**
     * Returns a string representation of this test case.
     *
     * @return a string representation
     */
    @Override
    public String toString() {
        return this.args.toString();
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyListObj;
import java.util.*;

/**
 * A node for generating Python list values.
 *
 * @param <InnerType> the type of elements within the generated lists
 */
public class PyListNode<InnerType extends APyObj> extends AIterablePyNode<PyListObj<InnerType>> {

    private final APyNode<InnerType> innerNode;

    public PyListNode(APyNode<InnerType> innerNode) {
        this.innerNode = innerNode;
    }

    @Override
    public APyNode<InnerType> getLeftChild() {
        return this.innerNode;
    }

    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyListObj<InnerType>> genExVals() {
        Set<PyListObj<InnerType>> result = new HashSet<>();
        List<InnerType> innerVals = new ArrayList<>(innerNode.genExVals());

        for (Object lenObj : this.exDomain) {
            int len = (Integer) lenObj;
            genSequences(innerVals, len, new ArrayList<>(), result);
        }
        return result;
    }

    @Override
    public PyListObj<InnerType> genRandVal() {
        Random rand = new Random();
        int len = (Integer) this.ranDomain.get(rand.nextInt(this.ranDomain.size()));

        List<InnerType> elements = new ArrayList<>();
        for (int i = 0; i < len; i++) {
            elements.add(innerNode.genRandVal());
        }
        return new PyListObj<>(elements);
    }

    /**
     * Recursively generates all sequences of the given length with repetition.
     */
    private void genSequences(List<InnerType> elements, int length,
                              List<InnerType> current, Set<PyListObj<InnerType>> result) {
        if (current.size() == length) {
            result.add(new PyListObj<>(new ArrayList<>(current)));
            return;
        }
        for (InnerType elem : elements) {
            current.add(elem);
            genSequences(elements, length, current, result);
            current.remove(current.size() - 1);
        }
    }
}

package main.rice.node;

import main.rice.obj.PyFloatObj;
import java.util.HashSet;
import java.util.Random;
import java.util.Set;

/**
 * A node for generating Python float values.
 */
public class PyFloatNode extends APyNode<PyFloatObj> {

    @Override
    public Set<PyFloatObj> genExVals() {
        Set<PyFloatObj> result = new HashSet<>();
        for (Object val : this.exDomain) {
            result.add(new PyFloatObj((Double) val));
        }
        return result;
    }

    @Override
    public PyFloatObj genRandVal() {
        Random rand = new Random();
        int idx = rand.nextInt(this.ranDomain.size());
        return new PyFloatObj((Double) this.ranDomain.get(idx));
    }
}

package main.rice.node;

import main.rice.obj.PyCharObj;
import main.rice.obj.PyStringObj;
import java.util.*;

/**
 * A node for generating Python string values.
 * Takes a string of allowed characters in its constructor rather than a child node.
 */
public class PyStringNode extends AIterablePyNode<PyStringObj> {

    private final String allowedChars;

    public PyStringNode(String allowedChars) {
        this.allowedChars = allowedChars;
    }

    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyStringObj> genExVals() {
        Set<PyStringObj> result = new HashSet<>();

        for (Object lenObj : this.exDomain) {
            int len = (Integer) lenObj;
            genStrings(len, new StringBuilder(), result);
        }
        return result;
    }

    @Override
    public PyStringObj genRandVal() {
        Random rand = new Random();
        int len = (Integer) this.ranDomain.get(rand.nextInt(this.ranDomain.size()));

        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < len; i++) {
            sb.append(allowedChars.charAt(rand.nextInt(allowedChars.length())));
        }
        return new PyStringObj(sb.toString());
    }

    /**
     * Recursively generates all strings of the given length from allowed characters.
     */
    private void genStrings(int length, StringBuilder current, Set<PyStringObj> result) {
        if (current.length() == length) {
            result.add(new PyStringObj(current.toString()));
            return;
        }
        for (int i = 0; i < allowedChars.length(); i++) {
            current.append(allowedChars.charAt(i));
            genStrings(length, current, result);
            current.deleteCharAt(current.length() - 1);
        }
    }
}

package main.rice.node;

import main.rice.obj.APyObj;

/**
 * An abstract class whose subclasses represent domains of possible iterable
 * Python values (lists, tuples, sets, strings, dicts).
 *
 * @param <ObjType> the type of Python object generated by this node
 */
public abstract class AIterablePyNode<ObjType extends APyObj> extends APyNode<ObjType> {

    /**
     * Returns the left child node (the inner element generator).
     *
     * @return the left child node
     */
    public abstract APyNode<?> getLeftChild();

    /**
     * Returns the right child node (used by dict nodes for the value generator).
     *
     * @return the right child node, or null if not applicable
     */
    public abstract APyNode<?> getRightChild();
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyTupleObj;
import java.util.*;

/**
 * A node for generating Python tuple values.
 *
 * @param <InnerType> the type of elements within the generated tuples
 */
public class PyTupleNode<InnerType extends APyObj> extends AIterablePyNode<PyTupleObj<InnerType>> {

    private final APyNode<InnerType> innerNode;

    public PyTupleNode(APyNode<InnerType> innerNode) {
        this.innerNode = innerNode;
    }

    @Override
    public APyNode<InnerType> getLeftChild() {
        return this.innerNode;
    }

    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyTupleObj<InnerType>> genExVals() {
        Set<PyTupleObj<InnerType>> result = new HashSet<>();
        List<InnerType> innerVals = new ArrayList<>(innerNode.genExVals());

        for (Object lenObj : this.exDomain) {
            int len = (Integer) lenObj;
            genSequences(innerVals, len, new ArrayList<>(), result);
        }
        return result;
    }

    @Override
    public PyTupleObj<InnerType> genRandVal() {
        Random rand = new Random();
        int len = (Integer) this.ranDomain.get(rand.nextInt(this.ranDomain.size()));

        List<InnerType> elements = new ArrayList<>();
        for (int i = 0; i < len; i++) {
            elements.add(innerNode.genRandVal());
        }
        return new PyTupleObj<>(elements);
    }

    /**
     * Recursively generates all sequences of the given length with repetition.
     */
    private void genSequences(List<InnerType> elements, int length,
                              List<InnerType> current, Set<PyTupleObj<InnerType>> result) {
        if (current.size() == length) {
            result.add(new PyTupleObj<>(new ArrayList<>(current)));
            return;
        }
        for (InnerType elem : elements) {
            current.add(elem);
            genSequences(elements, length, current, result);
            current.remove(current.size() - 1);
        }
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyDictObj;
import java.util.*;

/**
 * A node for generating Python dictionary values.
 * Has both a left child (key generator) and a right child (value generator).
 *
 * @param <KeyType> the type of keys in the generated dictionaries
 * @param <ValType> the type of values in the generated dictionaries
 */
public class PyDictNode<KeyType extends APyObj, ValType extends APyObj>
        extends AIterablePyNode<PyDictObj<KeyType, ValType>> {

    private final APyNode<KeyType> keyNode;
    private final APyNode<ValType> valNode;

    public PyDictNode(APyNode<KeyType> keyNode, APyNode<ValType> valNode) {
        this.keyNode = keyNode;
        this.valNode = valNode;
    }

    @Override
    public APyNode<KeyType> getLeftChild() {
        return this.keyNode;
    }

    @Override
    public APyNode<ValType> getRightChild() {
        return this.valNode;
    }

    @Override
    public Set<PyDictObj<KeyType, ValType>> genExVals() {
        Set<PyDictObj<KeyType, ValType>> result = new HashSet<>();
        List<KeyType> keyVals = new ArrayList<>(keyNode.genExVals());
        List<ValType> valVals = new ArrayList<>(valNode.genExVals());

        for (Object lenObj : this.exDomain) {
            int len = (Integer) lenObj;
            // Generate all key combinations of this size
            List<List<KeyType>> keyCombos = new ArrayList<>();
            genKeyCombinations(keyVals, len, 0, new ArrayList<>(), keyCombos);

            for (List<KeyType> keys : keyCombos) {
                // For each key combination, generate all value assignments
                genValueAssignments(valVals, keys, 0, new HashMap<>(), result);
            }
        }
        return result;
    }

    @Override
    public PyDictObj<KeyType, ValType> genRandVal() {
        Random rand = new Random();
        int len = (Integer) this.ranDomain.get(rand.nextInt(this.ranDomain.size()));

        // Generate random unique keys
        Set<KeyType> keySet = new LinkedHashSet<>();
        int maxAttempts = len * 100;
        int attempts = 0;
        while (keySet.size() < len && attempts < maxAttempts) {
            keySet.add(keyNode.genRandVal());
            attempts++;
        }

        // Assign random values
        Map<KeyType, ValType> map = new HashMap<>();
        for (KeyType key : keySet) {
            map.put(key, valNode.genRandVal());
        }
        return new PyDictObj<>(map);
    }

    /**
     * Recursively generates all combinations of keys of the given size.
     */
    private void genKeyCombinations(List<KeyType> keys, int size, int start,
                                    List<KeyType> current, List<List<KeyType>> result) {
        if (current.size() == size) {
            result.add(new ArrayList<>(current));
            return;
        }
        for (int i = start; i < keys.size(); i++) {
            current.add(keys.get(i));
            genKeyCombinations(keys, size, i + 1, current, result);
            current.remove(current.size() - 1);
        }
    }

    /**
     * Recursively generates all possible value assignments for the given key list.
     */
    private void genValueAssignments(List<ValType> values, List<KeyType> keys, int keyIdx,
                                     Map<KeyType, ValType> current,
                                     Set<PyDictObj<KeyType, ValType>> result) {
        if (keyIdx == keys.size()) {
            result.add(new PyDictObj<>(new HashMap<>(current)));
            return;
        }
        KeyType key = keys.get(keyIdx);
        for (ValType val : values) {
            current.put(key, val);
            genValueAssignments(values, keys, keyIdx + 1, current, result);
            current.remove(key);
        }
    }
}

