+package main.rice.node;
+
+import main.rice.obj.APyObj;
+import main.rice.obj.PySetObj;
+import java.util.*;
+
+/**
+ * A node for generating Python set values.
+ * Sets differ from lists/tuples in that they don't allow duplicate elements.
+ *
+ * @param <InnerType> the type of elements within the generated sets
+ */
+public class PySetNode<InnerType extends APyObj> extends AIterablePyNode<PySetObj<InnerType>> {
+
+    private final APyNode<InnerType> innerNode;
+
+    public PySetNode(APyNode<InnerType> innerNode) {
+        this.innerNode = innerNode;
+    }
+
+    @Override
+    public APyNode<InnerType> getLeftChild() {
+        return this.innerNode;
+    }
+
+    @Override
+    public APyNode<?> getRightChild() {
+        return null;
+    }
+
+    @Override
+    public Set<PySetObj<InnerType>> genExVals() {
+        Set<PySetObj<InnerType>> result = new HashSet<>();
+        List<InnerType> innerVals = new ArrayList<>(innerNode.genExVals());
+
+        for (Object lenObj : this.exDomain) {
+            int len = (Integer) lenObj;
+            genCombinations(innerVals, len, 0, new ArrayList<>(), result);
+        }
+        return result;
+    }
+
+    @Override
+    public PySetObj<InnerType> genRandVal() {
+        Random rand = new Random();
+        int len = (Integer) this.ranDomain.get(rand.nextInt(this.ranDomain.size()));
+
+        Set<InnerType> elements = new HashSet<>();
+        int maxAttempts = len * 100;
+        int attempts = 0;
+        while (elements.size() < len && attempts < maxAttempts) {
+            elements.add(innerNode.genRandVal());
+            attempts++;
+        }
+        return new PySetObj<>(elements);
+    }
+
+    /**
+     * Recursively generates all combinations (subsets) of the given size without repetition.
+     */
+    private void genCombinations(List<InnerType> elements, int size, int start,
+                                 List<InnerType> current, Set<PySetObj<InnerType>> result) {
+        if (current.size() == size) {
+            result.add(new PySetObj<>(new HashSet<>(current)));
+            return;
+        }
+        for (int i = start; i < elements.size(); i++) {
+            current.add(elements.get(i));
+            genCombinations(elements, size, i + 1, current, result);
+            current.remove(current.size() - 1);
+        }
+    }
+}
